import { useEffect, useState } from "react";
import { backendURL } from "../Globals";


let JournalsComponent = () => {

    let [journals, setJournals] = useState ([])
    let [message, setMessage] = useState("")


    useEffect ( () =>  {
        getJournals();
    }, [])


let getJournals = async () => {
    let response = await fetch(backendURL+"/journals") //aquí debería ser journals?apikey, pero para eso debería estar guardada en localstorage en LoginUSerComponent

    if (response.ok){
            let jsonData = await response.json()
            setJournals(jsonData)
    } else {
        setMessage("Error")
    }
}
return (
    <h2>Journals Component</h2>
)

}

export default JournalsComponent;
